import{_ as a,I as o,o as r,c as n,j as t,a as s,J as l,ap as u}from"./chunks/framework.1nQEiaeB.js";const k=JSON.parse('{"title":"Contribute","description":"How to contribute to the Citizen skin.","frontmatter":{"title":"Contribute","description":"How to contribute to the Citizen skin."},"headers":[],"relativePath":"contribute/index.md","filePath":"contribute/index.md","lastUpdated":1773260037000}'),c={name:"contribute/index.md"};function h(d,e,m,p,b,f){const i=o("CopyOrDownloadAsMarkdownButtons");return r(),n("div",null,[e[0]||(e[0]=t("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /v3.16/contribute.md for this page in Markdown format",-1)),e[1]||(e[1]=t("h1",{id:"contributing",tabindex:"-1"},[s("Contributing "),t("a",{class:"header-anchor",href:"#contributing","aria-label":"Permalink to “Contributing”"},"​")],-1)),l(i),e[2]||(e[2]=u('<p>Thank you for considering contributing to <em>Citizen</em>!</p><p><em>Citizen</em> is a small open-source project, and we appreciate any help. Here are some ways you can contribute:</p><ul><li><a href="https://github.com/StarCitizenTools/mediawiki-skins-Citizen/pulls" target="_blank" rel="noreferrer">Code patches</a></li><li><a href="https://mwcitizen.skin/" target="_blank" rel="noreferrer">Documentation improvements</a></li><li><a href="https://github.com/StarCitizenTools/mediawiki-skins-Citizen/issues/new?template=bug_report.yml" target="_blank" rel="noreferrer">Bug reports</a></li><li><a href="https://github.com/StarCitizenTools/mediawiki-skins-Citizen/issues/new?template=feature_request.yml" target="_blank" rel="noreferrer">Feature requests and suggestions</a></li><li><a href="#translations">Translations</a></li></ul><h2 id="how-to-submit-a-contribution" tabindex="-1">How to submit a contribution <a class="header-anchor" href="#how-to-submit-a-contribution" aria-label="Permalink to “How to submit a contribution”">​</a></h2><ol><li><a href="https://github.com/StarCitizenTools/mediawiki-skins-Citizen/fork" target="_blank" rel="noreferrer">Fork</a> the <em>Citizen</em> repository.</li><li>Create a new branch in your fork to make your changes.</li><li>Commit your changes to your new branch.</li><li>Push your changes to your fork on GitHub.</li><li>Submit a pull request from your branch to the <em>Citizen</em> repository.</li></ol><p>We will review your pull request and, if everything looks good, merge it into the main codebase.</p><h2 id="ai-assisted-contributions" tabindex="-1">AI-assisted contributions <a class="header-anchor" href="#ai-assisted-contributions" aria-label="Permalink to “AI-assisted contributions”">​</a></h2><p>The maintainers of <em>Citizen</em> use AI tools (such as LLMs and code assistants) as part of their development workflow. Contributors are welcome to do the same, subject to the following expectations:</p><h3 id="human-accountability" tabindex="-1">Human accountability <a class="header-anchor" href="#human-accountability" aria-label="Permalink to “Human accountability”">​</a></h3><p>The person submitting a contribution is fully responsible for it, regardless of how it was produced. If you use AI to help write code, you must understand what the code does, verify that it works, and be prepared to maintain it.</p><h3 id="licensing-and-copyright" tabindex="-1">Licensing and copyright <a class="header-anchor" href="#licensing-and-copyright" aria-label="Permalink to “Licensing and copyright”">​</a></h3><p>You must ensure that your contribution is compatible with the project&#39;s license (<a href="https://github.com/StarCitizenTools/mediawiki-skins-Citizen/blob/main/LICENSE" target="_blank" rel="noreferrer">GPL-3.0-or-later</a>) and does not incorporate third-party code in a way that violates its copyright or license terms. This applies to all contributions — whether written by hand, copied from a reference, or generated with a tool.</p><h3 id="quality-over-volume" tabindex="-1">Quality over volume <a class="header-anchor" href="#quality-over-volume" aria-label="Permalink to “Quality over volume”">​</a></h3><p>Every submission should be purposeful, well-tested, and reviewed for correctness, style, and fit with the project. PRs that appear to be unreviewed AI output — large dumps of generated code, generic boilerplate, or changes that ignore the project&#39;s conventions — will be closed.</p><h3 id="communication" tabindex="-1">Communication <a class="header-anchor" href="#communication" aria-label="Permalink to “Communication”">​</a></h3><p>Commit messages, PR descriptions, and review comments should be clear, specific, and relevant — regardless of how they were drafted. Generic filler like &quot;This PR improves code quality and enhances maintainability&quot; tells reviewers nothing. Make sure your communication actually describes what changed and why.</p><h2 id="translations" tabindex="-1">Translations <a class="header-anchor" href="#translations" aria-label="Permalink to “Translations”">​</a></h2><p>You can submit translations via <a href="https://translatewiki.net/w/i.php?title=Special:Translate&amp;group=mwgithub-star-citizen" target="_blank" rel="noreferrer">TranslateWiki.net</a>. They are usually merged bi-weekly.</p><h2 id="questions" tabindex="-1">Questions <a class="header-anchor" href="#questions" aria-label="Permalink to “Questions”">​</a></h2><p>If you have any questions about contributing, feel free to <a href="https://github.com/StarCitizenTools/mediawiki-skins-Citizen/issues/new/choose" target="_blank" rel="noreferrer">open an issue</a> and ask.</p><h2 id="contributors" tabindex="-1">Contributors <a class="header-anchor" href="#contributors" aria-label="Permalink to “Contributors”">​</a></h2><a href="https://github.com/StarCitizenTools/mediawiki-skins-citizen/graphs/contributors"><img src="https://contrib.rocks/image?repo=StarCitizenTools/mediawiki-skins-citizen" alt="Citizen contributors" title="Citizen contributors" width="812px"></a>',22))])}const w=a(c,[["render",h]]);export{k as __pageData,w as default};
